import Foundationimport AVFoundationimport Photosimport CoreLocationactor CameraPermissions {    nonisolated(unsafe) static let shared = CameraPermissions()()        enum PermissionStatus {        case authorized        case denied        case notDetermined        case restricted    }        var cameraStatus: PermissionStatus {        get async {            let status = AVCaptureDevice.authorizationStatus(for: .video)            switch status {            case .authorized: return .authorized            case .denied: return .denied            case .notDetermined: return .notDetermined            case .restricted: return .restricted            @unknown default: return .notDetermined            }        }    }        var microphoneStatus: PermissionStatus {        get async {            let status = AVCaptureDevice.authorizationStatus(for: .audio)            switch status {            case .authorized: return .authorized            case .denied: return .denied            case .notDetermined: return .notDetermined            case .restricted: return .restricted            @unknown default: return .notDetermined            }        }    }        var photoLibraryStatus: PermissionStatus {        get async {            let status = PHPhotoLibrary.authorizationStatus(for: .addOnly)            switch status {            case .authorized, .limited: return .authorized            case .denied: return .denied            case .notDetermined: return .notDetermined            case .restricted: return .restricted            @unknown default: return .notDetermined            }        }    }        func requestCameraAccess() async -> Bool {        let status = await cameraStatus        if status == .notDetermined {            return await AVCaptureDevice.requestAccess(for: .video)        }        return status == .authorized    }        func requestMicrophoneAccess() async -> Bool {        let status = await microphoneStatus        if status == .notDetermined {            return await AVCaptureDevice.requestAccess(for: .audio)        }        return status == .authorized    }        func requestPhotoLibraryAccess() async -> Bool {        let status = await photoLibraryStatus        if status == .notDetermined {            let result = await PHPhotoLibrary.requestAuthorization(for: .addOnly)            return result == .authorized || result == .limited        }        return status == .authorized    }        func requestAllPermissions() async -> (camera: Bool, microphone: Bool, photos: Bool) {        async let camera = requestCameraAccess()        async let microphone = requestMicrophoneAccess()        async let photos = requestPhotoLibraryAccess()        return await (camera, microphone, photos)    }}